pub type SetToStatementContextAll<'input> = SetToStatementContext<'input>;


pub type SetToStatementContext<'input> = BaseParserRuleContext<'input,SetToStatementContextExt<'input>>;

#[derive(Clone)]
pub struct SetToStatementContextExt<'input>{
ph:PhantomData<&'input str>
}

impl<'input> Cobol85ParserContext<'input> for SetToStatementContext<'input>{}

impl<'input,'a> Listenable<dyn Cobol85Listener<'input> + 'a> for SetToStatementContext<'input>{
		fn enter(&self,listener: &mut (dyn Cobol85Listener<'input> + 'a)) {
			listener.enter_every_rule(self);
			listener.enter_setToStatement(self);
		}
		fn exit(&self,listener: &mut (dyn Cobol85Listener<'input> + 'a)) {
			listener.exit_setToStatement(self);
			listener.exit_every_rule(self);
		}
}

impl<'input,'a> Visitable<dyn Cobol85Visitor<'input> + 'a> for SetToStatementContext<'input>{
	fn accept(&self,visitor: &mut (dyn Cobol85Visitor<'input> + 'a)) {
		visitor.visit_setToStatement(self);
	}
}

impl<'input> CustomRuleContext<'input> for SetToStatementContextExt<'input>{
	type TF = LocalTokenFactory<'input>;
	type Ctx = Cobol85ParserContextType;
	fn get_rule_index(&self) -> usize { RULE_setToStatement }
	//fn type_rule_index() -> usize where Self: Sized { RULE_setToStatement }
}
antlr_rust::tid!{SetToStatementContextExt<'a>}

impl<'input> SetToStatementContextExt<'input>{
	fn new(parent: Option<Rc<dyn Cobol85ParserContext<'input> + 'input > >, invoking_state: isize) -> Rc<SetToStatementContextAll<'input>> {
		Rc::new(
			BaseParserRuleContext::new_parser_ctx(parent, invoking_state,SetToStatementContextExt{
				ph:PhantomData
			}),
		)
	}
}

