pub struct StringSendingPhraseContextExt<'input>{
ph:PhantomData<&'input str>
}

impl<'input> Cobol85ParserContext<'input> for StringSendingPhraseContext<'input>{}

impl<'input,'a> Listenable<dyn Cobol85Listener<'input> + 'a> for StringSendingPhraseContext<'input>{
		fn enter(&self,listener: &mut (dyn Cobol85Listener<'input> + 'a)) {
			listener.enter_every_rule(self);
			listener.enter_stringSendingPhrase(self);
		}
		fn exit(&self,listener: &mut (dyn Cobol85Listener<'input> + 'a)) {
			listener.exit_stringSendingPhrase(self);
			listener.exit_every_rule(self);
		}
}

