pub type CommentEntryContext<'input> = BaseParserRuleContext<'input,CommentEntryContextExt<'input>>;

#[derive(Clone)]
pub struct CommentEntryContextExt<'input>{
ph:PhantomData<&'input str>
}

impl<'input> Cobol85ParserContext<'input> for CommentEntryContext<'input>{}

impl<'input,'a> Listenable<dyn Cobol85Listener<'input> + 'a> for CommentEntryContext<'input>{
		fn enter(&self,listener: &mut (dyn Cobol85Listener<'input> + 'a)) {
			listener.enter_every_rule(self);
			listener.enter_commentEntry(self);
		}
		fn exit(&self,listener: &mut (dyn Cobol85Listener<'input> + 'a)) {
			listener.exit_commentEntry(self);
			listener.exit_every_rule(self);
		}
}

impl<'input,'a> Visitable<dyn Cobol85Visitor<'input> + 'a> for CommentEntryContext<'input>{
	fn accept(&self,visitor: &mut (dyn Cobol85Visitor<'input> + 'a)) {
		visitor.visit_commentEntry(self);
	}
}

